async exportExcel(isTemp, sheetName, sheetProperties) {
      let originSheetProperties = {
        maxRow: 66, //最大行数
      };
      if (!!sheetProperties) {
        originSheetProperties = {
          ...originSheetProperties,
          ...sheetProperties,
        };
      }

      const workbook = new ExcelJS.Workbook();
      if (!!!sheetName) {
        sheetName = "sheet1";
      }
      debugger;
      // 创建一个工作表
      let worksheet = workbook.addWorksheet(isTemp ? "导入模版" : sheetName, {
        views: [{ state: "frozen", xSplit: 4, ySplit: 1 }],
      });
      worksheet.properties.defaultColWidth = 15;
      let beginColumn = "A";
      let dictColumnMapping = {};

      // 设置表头
      let headerColumns = [];
      for (let i = 0; i < this.columns.length; i++) {
        const column = this.columns[i];
        //到处列表展示的列
        if (this.handelShow(column.visible, column.role)) {
          headerColumns.push({
            header: column.label.trim(),
            key: column.prop,
            width: column.excelWidth || 15,
          });
          if ("options" in column || "dictType" in column) {
            dictColumnMapping[column.prop] = beginColumn;
          }
          beginColumn = String.fromCharCode(beginColumn.charCodeAt(0) + 1);
        }
      }
      // 插入表头
      worksheet.columns = headerColumns;

      if (isTemp) {
        worksheet.addRow([1]);
      } else {
        this.tableData.forEach((item) => {
          worksheet.addRow(item);
        });
      }

      // 添加第二个工作表用于存放下拉菜单选项
      const worksheet2 = workbook.addWorksheet("字典支持数据");
      const dictMap = this.verifyColumnsContainsProp();
      let dictsMapping = {};
      beginColumn = "A";

      for (const key in dictMap) {
        if (Object.prototype.hasOwnProperty.call(dictMap, key)) {
          const dictLabels = dictMap[key].map((item) => item.label);
          worksheet2.getColumn(beginColumn).values = [...dictLabels]; // 避免覆盖标题行
          dictsMapping[key] = beginColumn;
          beginColumn = String.fromCharCode(beginColumn.charCodeAt(0) + 1);
        }
      }

      // 设置数据验证

      for (const key in dictColumnMapping) {
        const col = worksheet.getColumn(dictColumnMapping[key]);
        const dictLength = dictMap[key].length;

        const dictLabels = dictMap[key].map((item) => item.label);
        const dictData = '"' + Object.values(dictLabels).join(",") + '"';
        for (let row = 2; row <= originSheetProperties.maxRow; row++) {
          worksheet.getCell(`${dictColumnMapping[key]}${row}`).dataValidation =
            {
              type: "list",
              allowBlank: true,
              // formulae: ['"' + Object.values(dictLabels).join(",") + '"'],
              formulae: [ `='字典支持数据'!${dictsMapping[key]}1:${dictsMapping[key]}${dictMap[key].length}`],
            };
          console.log(
            `='字典支持数据'!${dictsMapping[key]}1:${dictsMapping[key]}${dictMap[key].length}`
          );
        }
      }

